mapper.select:
select id, tenant_id as tenantId, delivery_no as deliveryNo, line_sign as lineSign,
       qty_cap as qtyCap, create_time as createTime, update_time as updateTime
from stk_delivery_line_cap
where tenant_id = #{tenantId}
  and delivery_no = #{deliveryNo}
  and line_sign = #{lineSign}
limit 1
